import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def get_packages(data):
    result = {}
    for proj in data.get('projects', []):
        pname = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            for pkg in fw.get('topLevelPackages', []):
                key = (pname, fw['framework'], pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = get_packages(baseline)
a = get_packages(after)
all_keys = sorted(set(b.keys()) | set(a.keys()))
changes = []
unchanged = []
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv != av:
        changes.append((k[0], k[1], k[2], bv or 'N/A', av or 'N/A'))
    else:
        unchanged.append((k[0], k[1], k[2], bv))

print('=== CHANGES ===')
if changes:
    for c in changes: print(f'{c[0]:20} {c[1]:8} {c[2]:50} {c[3]:10} -> {c[4]}')
else:
    print('None')
print()
print(f'=== UNCHANGED: {len(unchanged)} packages ===')" 2>&1

